import os
import time
import logging
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ApiError, TransportError

APP_NAME = os.getenv("APP_NAME", "product-search-api")
ES_URL = os.getenv("ES_URL", "http://localhost:9200")
ES_USER = os.getenv("ES_USER")
ES_PASSWORD = os.getenv("ES_PASSWORD")
ES_API_KEY = os.getenv("ES_API_KEY")
ES_INDEX = os.getenv("ES_INDEX", "products")
ES_REQUEST_TIMEOUT = float(os.getenv("ES_REQUEST_TIMEOUT", "0.8"))
ES_MAX_RETRIES = int(os.getenv("ES_MAX_RETRIES", "2"))
ES_RETRY_ON_TIMEOUT = os.getenv("ES_RETRY_ON_TIMEOUT", "true").lower() == "true"

DEFAULT_SIZE = int(os.getenv("DEFAULT_SIZE", "20"))
MAX_SIZE = int(os.getenv("MAX_SIZE", "50"))
MAX_Q_LEN = int(os.getenv("MAX_Q_LEN", "128"))

logging.basicConfig(level=os.getenv("LOG_LEVEL", "INFO"))
logger = logging.getLogger(APP_NAME)

app = Flask(APP_NAME)

_es_kwargs = {
    "hosts": [ES_URL],
    "request_timeout": ES_REQUEST_TIMEOUT,
    "max_retries": ES_MAX_RETRIES,
    "retry_on_timeout": ES_RETRY_ON_TIMEOUT,
}
if ES_API_KEY:
    _es_kwargs["api_key"] = ES_API_KEY
elif ES_USER is not None and ES_PASSWORD is not None:
    _es_kwargs["basic_auth"] = (ES_USER, ES_PASSWORD)

es = Elasticsearch(**_es_kwargs)


def _clamp_int(v, default, lo=None, hi=None):
    try:
        i = int(v)
    except Exception:
        return default
    if lo is not None and i < lo:
        i = lo
    if hi is not None and i > hi:
        i = hi
    return i


def _sanitize_q(q: str) -> str:
    q = (q or "").strip()
    if len(q) > MAX_Q_LEN:
        q = q[:MAX_Q_LEN]
    return q


def _build_query(q: str):
    if not q:
        return {"match_none": {}}

    return {
        "bool": {
            "should": [
                {
                    "multi_match": {
                        "query": q,
                        "type": "best_fields",
                        "operator": "and",
                        "fields": [
                            "name^5",
                            "name.keyword^10",
                            "brand^3",
                            "categories^2",
                            "tags^2",
                            "description",
                        ],
                        "fuzziness": "AUTO",
                        "prefix_length": 1,
                    }
                },
                {
                    "multi_match": {
                        "query": q,
                        "type": "phrase_prefix",
                        "fields": [
                            "name^6",
                            "brand^3",
                            "categories^2",
                            "tags^2",
                        ],
                        "max_expansions": 50,
                    }
                },
            ],
            "minimum_should_match": 1,
            "filter": [
                {"term": {"is_active": True}},
            ],
        }
    }


def _extract_products(resp):
    hits = (resp or {}).get("hits", {}).get("hits", [])
    products = []
    for h in hits:
        src = h.get("_source") or {}
        products.append(
            {
                "id": h.get("_id") or src.get("id"),
                "score": h.get("_score"),
                "name": src.get("name"),
                "brand": src.get("brand"),
                "price": src.get("price"),
                "currency": src.get("currency"),
                "image_url": src.get("image_url"),
                "url": src.get("url"),
                "categories": src.get("categories"),
                "tags": src.get("tags"),
                "in_stock": src.get("in_stock"),
            }
        )
    return products


@app.get("/api/search")
def search_products():
    start = time.perf_counter()

    q = _sanitize_q(request.args.get("q", ""))
    size = _clamp_int(request.args.get("size"), DEFAULT_SIZE, 1, MAX_SIZE)
    page = _clamp_int(request.args.get("page"), 1, 1, 1000)
    from_ = (page - 1) * size

    if not q:
        return jsonify({"error": "Missing required parameter: q"}), 400

    body = {
        "track_total_hits": False,
        "timeout": f"{int(ES_REQUEST_TIMEOUT * 1000)}ms",
        "query": _build_query(q),
        "_source": {
            "includes": [
                "id",
                "name",
                "brand",
                "price",
                "currency",
                "image_url",
                "url",
                "categories",
                "tags",
                "in_stock",
                "is_active",
            ]
        },
        "from": from_,
        "size": size,
    }

    try:
        resp = es.search(index=ES_INDEX, body=body)
        products = _extract_products(resp)
        took_ms = (time.perf_counter() - start) * 1000.0
        return (
            jsonify(
                {
                    "query": q,
                    "page": page,
                    "size": size,
                    "count": len(products),
                    "took_ms": round(took_ms, 2),
                    "products": products,
                }
            ),
            200,
            {
                "Cache-Control": "public, max-age=1",
                "X-Query-Time-Ms": f"{took_ms:.2f}",
            },
        )
    except (ApiError, TransportError) as e:
        took_ms = (time.perf_counter() - start) * 1000.0
        logger.exception("Elasticsearch error", extra={"took_ms": took_ms, "q": q})
        return (
            jsonify(
                {
                    "error": "Search backend unavailable",
                    "took_ms": round(took_ms, 2),
                }
            ),
            503,
            {
                "Retry-After": "1",
                "Cache-Control": "no-store",
                "X-Query-Time-Ms": f"{took_ms:.2f}",
            },
        )


